def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres = Presentation(modified_ppt_path)
    if len(pres.slides) < 5:
        return ("Slide 5 is missing in the presentation.", 0)
    slide = pres.slides[4]
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue

        # Collect all paragraphs with their levels
        paragraphs = []
        for p in shape.text_frame.paragraphs:
            if p.text.strip():
                paragraphs.append((p.text.strip(), p.level))

        # Find Expenses bullet and then find Capital bullet after it at the same level
        expenses_index = -1
        for i, (text, level) in enumerate(paragraphs):
            if text == 'Expenses' and level == 1:
                expenses_index = i
                break

        if expenses_index >= 0:
            # Look for Capital bullet after Expenses at level 1 (main bullet level)
            for i in range(expenses_index + 1, len(paragraphs)):
                text, level = paragraphs[i]
                if level == 1 and text == 'Capital':
                    return ("'Capital' bullet appears after 'Expenses' bullet on slide 5.", 1)

    return ("'Capital' bullet is not placed after 'Expenses' on slide 5.", 0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres_orig = Presentation(original_ppt_path)
    pres_mod = Presentation(modified_ppt_path)
    if len(pres_orig.slides) < 5 or len(pres_mod.slides) < 5:
        return ("Slide 5 missing in one of the presentations.", 0)
    slide_orig = pres_orig.slides[4]
    slide_mod = pres_mod.slides[4]
    def extract_bullets(slide):
        bullets = []
        for shape in slide.shapes:
            if not shape.has_text_frame:
                continue
            for paragraph in shape.text_frame.paragraphs:
                txt = paragraph.text.strip()
                if txt:
                    bullets.append(txt)
        return bullets
    orig_bullets = extract_bullets(slide_orig)
    mod_bullets = extract_bullets(slide_mod)
    # Remove 'Capital' from list for diff check
    mod_bullets_minus_capital = [b for b in mod_bullets if b != 'Capital']
    # Now compare
    if orig_bullets == mod_bullets_minus_capital:
        return ("No other bullets were modified on slide 5 except 'Capital' was added.", 1)
    else:
        return ("Other bullets were modified/added/removed on slide 5.", 0)

