            changed_slides.add(s.slide_number)
    for s in ppt_diff.removed_slides:
        if s.slide_number != 5:
            changed_slides.add(s.slide_number)
    for mod in ppt_diff.modified_slides:
        orig, mod_ = mod
        if orig.slide_number != 5:
            changed_slides.add(orig.slide_number)
    if changed_slides:
