    return ("No changes to slides other than 5.", 1)

def compute_score() -> tuple[str, float]:
    # Check for animation additions/removals which are not allowed for this task
    if ppt_diff.added_animations or ppt_diff.removed_animations:
        return ("Extraneous animations were added or removed.", 0)

    # For transitions, we'll be more lenient as some tools modify these during save
    # Only flag if there are major changes (additions, not just removals)
    if ppt_diff.added_transitions:
        return ("Extraneous transitions were added.", 0)

    return ("No extraneous animations or transitions were added.", 1)
